+static EGLBoolean QueryVendorDevices(__EGLvendorInfo *vendor, EGLint max_devices,
+        EGLDeviceEXT *devices, EGLint *num_devices)
+{
+    EGLDeviceEXT *vendorDevices = NULL;
+    EGLint vendorCount = 0;
+    EGLint i;
