commit dd2d28a033857cc303415a96141fb6d71121e530
Author: Kyle Brenneman <kbrenneman@nvidia.com>
Date:   Thu Nov 19 11:17:27 2020 -0700

    GLX: Fix a potential deadlock in OnDisplayClosed.

    In OnDisplayClosed, unlock the __glXDisplayInfoHash lock before locking
    glxContextHashLock.

    In CommonMakeCurrent, it holds glxContextHashLock while it tries to take the
    __glXDisplayInfoHash lock, so if CommonMakeCurrent and OnDisplayClosed run at
    the same time, they could deadlock.

    To avoid that, OnDisplayClosed will set a new inTeardown flag in the
    __GLXdisplayInfoHash, then it will unlock the display hash before calling
    __glXDisplayClosed.

    After __glXDisplayClosed is finished, OnDisplayClosed will lock
    __glXDisplayInfoHash again long enough to remove the display from the
    hashtable.

    The inTeardown flag tells __glXLookupDisplay to return NULL, since after that
    point, nothing should be trying to look up the display. In principle, we could
    just remove the display from the hashtable up front, but then if something did
    try to look up the display, then __glXLookupDisplay would try to create a new
    __GLXdisplayInfo for it.

    Fixes https://gitlab.freedesktop.org/glvnd/libglvnd/-/issues/213
---
 src/GLX/libglxmapping.c | 27 +++++++++++++++++++++++----
 1 file changed, 23 insertions(+), 4 deletions(-)

diff --git a/src/GLX/libglxmapping.c b/src/GLX/libglxmapping.c
index be384f8..24d9142 100644
--- a/src/GLX/libglxmapping.c
+++ b/src/GLX/libglxmapping.c
@@ -95,6 +95,7 @@ static DEFINE_INITIALIZED_LKDHASH(__GLXvendorNameHash, __glXVendorNameHash);

 typedef struct __GLXdisplayInfoHashRec {
     __GLXdisplayInfo info;
+    Bool inTeardown;
     UT_hash_handle hh;
 } __GLXdisplayInfoHash;

@@ -697,15 +698,27 @@ static int OnDisplayClosed(Display *dpy, XExtCodes *codes)

     LKDHASH_WRLOCK(__glXDisplayInfoHash);

+    // Set the inTeardown flag for this display, but don't remove it from the
+    // hashtable yet. We shouldn't try to look up this display after this, but
+    // just in case something does, we don't want to try to set up a new
+    // __GLXdisplayInfoHash struct for it.
     HASH_FIND_PTR(_LH(__glXDisplayInfoHash), &dpy, pEntry);
     if (pEntry != NULL) {
-        __glXDisplayClosed(&pEntry->info);
-        HASH_DEL(_LH(__glXDisplayInfoHash), pEntry);
+        assert(!pEntry->inTeardown);
+        pEntry->inTeardown = True;
     }
     LKDHASH_UNLOCK(__glXDisplayInfoHash);

-    CleanupDisplayInfoEntry(NULL, pEntry);
-    free(pEntry);
+    if (pEntry != NULL) {
+        __glXDisplayClosed(&pEntry->info);
+
+        // Now, we can remove the display from the hashtable and free it.
+        LKDHASH_WRLOCK(__glXDisplayInfoHash);
+        HASH_DEL(_LH(__glXDisplayInfoHash), pEntry);
+        LKDHASH_UNLOCK(__glXDisplayInfoHash);
+        CleanupDisplayInfoEntry(NULL, pEntry);
+        free(pEntry);
+    }

     return 0;
 }
@@ -724,6 +737,12 @@ __GLXdisplayInfo *__glXLookupDisplay(Display *dpy)
     LKDHASH_UNLOCK(__glXDisplayInfoHash);

     if (pEntry != NULL) {
+        if (pEntry->inTeardown) {
+            // This shouldn't happen: If we're in the process of tearing down a
+            // display, then we shouldn't be trying to look up the display
+            // again.
+            return NULL;
+        }
         return &pEntry->info;
     }

