 	-I$(top_srcdir)/include \
-	-I$(top_srcdir)/src/GLdispatch
+	-I$(top_srcdir)/src/GLdispatch \
+	$(PTHREAD_CFLAGS)
 testgldispatch_LDADD = $(top_builddir)/src/GLdispatch/libGLdispatch.la
