+++ b/src/EGL/libegl.c
@@ -165,6 +165,10 @@ static EGLBoolean IsGbmDisplay(void *native_display)
         return EGL_FALSE;
     }

+    if (!info.dli_sname) {
+        return EGL_FALSE;
+    }
+
     return !strcmp(info.dli_sname, "gbm_create_device");
 }

@@ -197,6 +201,10 @@ static EGLBoolean IsWaylandDisplay(void *native_display)
         return EGL_FALSE;
     }

+    if (!info.dli_sname) {
+        return EGL_FALSE;
+    }
+
     return !strcmp(info.dli_sname, "wl_display_interface");
 }

commit 28e05b934903ac9ea104ddda3ef79e6103ca8456
Author: Kyle Brenneman <kbrenneman@nvidia.com>
Date:   Thu Feb 22 11:33:43 2018 -0700

    Always return an error from eglMakeCurrent if the EGLDispaly is invalid

    In eglMakeCurrent, check to make sure the EGLDisplay is valid, even if the
    context is NULL.

    Fixes https://github.com/NVIDIA/libglvnd/issues/151
---
 src/EGL/libegl.c           | 16 +++++++++-------
 tests/testeglmakecurrent.c |  4 ++--
 2 files changed, 11 insertions(+), 9 deletions(-)

diff --git a/src/EGL/libegl.c b/src/EGL/libegl.c
index 6586ada..db595f6 100644
--- a/src/EGL/libegl.c
+++ b/src/EGL/libegl.c
@@ -642,6 +642,15 @@ PUBLIC EGLBoolean EGLAPIENTRY eglMakeCurrent(EGLDisplay dpy,

     __eglEntrypointCommon();

+    // According to the EGL spec, the display handle must be valid, even if
+    // the context is NULL.
+    newDpy = __eglLookupDisplay(dpy);
+    if (newDpy == NULL) {
+        __eglReportError(EGL_BAD_DISPLAY, "eglMakeCurrent", NULL,
+                "Invalid display %p", dpy);
+        return EGL_FALSE;
+    }
