 #endif
 }

+static void *SafeDereference(void *ptr)
+{
+    if (_eglPointerIsDereferencable(ptr))
+        return *((void **)ptr);
+    return NULL;
+}
+
+static EGLBoolean IsX11Display(void *dpy)
+{
+    void *alloc;
+    void *handle;
+    void *XAllocID;
