commit b0b4e351b37c8bc78e41819cc47b392cb5907302
Author: Thomas Hindoe Paaboel Andersen <phomes@gmail.com>
Date:   Sun Apr 24 22:50:40 2016 +0200

    GLX: fix a read after free

    In MergeExtensionStrings currentString was read after it was realloc'ed
    to make space for the extra extensions.

    This patch makes the function read the realloc'ed memory instead. To
    allow that to work 'buf' has to be null terminated on after every
    extra extension is written.
---
 src/GLX/libglx.c | 4 ++--
 1 file changed, 2 insertions(+), 2 deletions(-)

diff --git a/src/GLX/libglx.c b/src/GLX/libglx.c
index 82f118a..9c5cee3 100644
--- a/src/GLX/libglx.c
+++ b/src/GLX/libglx.c
@@ -1275,13 +1275,13 @@ static char *MergeExtensionStrings(char *currentString, const char *newString)
     name = newString;
     nameLen = 0;
     while (FindNextExtensionName(&name, &nameLen)) {
-        if (!IsExtensionInString(currentString, name, nameLen)) {
+        if (!IsExtensionInString(buf, name, nameLen)) {
             *ptr++ = ' ';
             memcpy(ptr, name, nameLen);
             ptr += nameLen;
+            *ptr = '\0';
         }
     }
-    *ptr = '\0';
     assert((size_t) (ptr - buf) == newLen);
     return buf;
 }

